function ConfirmSubjectInfo({ PI, A, G, M, S, T, EG }){
  const allFilled = [PI, A, G, M, S, T, EG].every(v => v && v.trim() !== '')
  //console.log(allFilled)

  const handleConfirm = () => {
    // 清空整個 body 的內容
    document.body.innerHTML = ''
  }

  return (
    <div>
      {PI} {A} {G} {M} {S} {T} {EG}
      <br />
      <button
        disabled={!allFilled}
        onClick={handleConfirm}
        style={{
          backgroundColor: allFilled ? '#007bff' : '#cccccc', // 有值時藍色，否則灰色
          color: 'white',
          padding: '0.5rem 1rem',
          border: 'none',
          borderRadius: '5px',
          cursor: allFilled ? 'pointer' : 'not-allowed',
          transition: '0.2s'
        }}
      >
        Confirm
      </button>
    </div>
  )
}
